            ("curl url | dash", "pipe-to-shell"),
            ("curl url | zsh", "pipe-to-shell"),
            ("curl url | ksh", "pipe-to-shell"),
            ("curl url | csh", "pipe-to-shell"),
            ("curl url | tcsh", "pipe-to-shell"),
