class TestMain:
    def test_blocked_command_exits_2(self, monkeypatch: pytest.MonkeyPatch) -> None:
        data = {"tool_input": {"command": "git push origin main"}}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        with pytest.raises(SystemExit) as exc_info:
            block_commands.main()
        assert exc_info.value.code == 2

    def test_allowed_command_exits_normally(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {"tool_input": {"command": "git status"}}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_commands.main()  # should not raise

    def test_empty_command_exits_normally(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {"tool_input": {"command": ""}}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_commands.main()  # should not raise

    def test_no_command_field_exits_normally(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {"tool_input": {}}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_commands.main()  # should not raise

    def test_no_tool_input_exits_normally(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {"tool_name": "Bash"}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_commands.main()  # should not raise

    def test_bad_json_no_crash(self, monkeypatch: pytest.MonkeyPatch) -> None:
        monkeypatch.setattr(sys, "stdin", io.StringIO("not json"))
        block_commands.main()  # should not raise

    def test_empty_stdin_no_crash(self, monkeypatch: pytest.MonkeyPatch) -> None:
        monkeypatch.setattr(sys, "stdin", io.StringIO(""))
        block_commands.main()  # should not raise

    def test_blocked_message_on_stderr(
        self, monkeypatch: pytest.MonkeyPatch, capsys: pytest.CaptureFixture[str]
    ) -> None:
        data = {"tool_input": {"command": "sudo rm -rf /"}}
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        with pytest.raises(SystemExit):
            block_commands.main()
        captured = capsys.readouterr()
        assert "BLOCKED: sudo is not allowed" in captured.err
